import { createHash } from 'crypto'
import { prisma } from '@/lib/prisma'
import { supabaseAdmin } from '@/lib/supabase/admin'
import { MCP_ERROR, type AuthResult } from '../errors'

export async function verifyPat(authHeader: string | null): Promise<AuthResult> {
  if (!authHeader) {
    return { ok: false, errorCode: MCP_ERROR.AUTH_REQUIRED, message: 'Authentication required' }
  }
  const token = authHeader.replace(/^Bearer\s+/i, '').trim()
  if (!token.startsWith('trmdict_pat_')) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Invalid token format' }
  }
  const tokenHash = createHash('sha256').update(token).digest('hex')
  const row = await prisma.tbTrmMcpToken.findUnique({ where: { tokenHash } })
  if (!row) return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Invalid token' }
  if (row.revokedAt) return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Token revoked' }
  if (row.expiresAt && row.expiresAt < new Date()) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Token expired' }
  }
  const { data, error } = await supabaseAdmin.auth.admin.getUserById(row.userId)
  if (error || !data.user) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'User not found' }
  }
  const role = (data.user.app_metadata?.role as 'USER' | 'ADMIN' | undefined) ?? 'USER'
  void prisma.tbTrmMcpToken.update({ where: { id: row.id }, data: { lastUsedAt: new Date() } })
  return { ok: true, tokenId: row.id, userId: row.userId, role }
}

